import React from "react";
import "./Banner.css";

import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, Pagination, Navigation } from "swiper/modules";

import "swiper/css";
import "swiper/css/pagination";
import "swiper/css/navigation";

function Banner() {
  return (
    <div className="banner">

      <Swiper
        modules={[Autoplay, Pagination, Navigation]}
        spaceBetween={10}
        slidesPerView={1}
        autoplay={{
          delay: 50,
          disableOnInteraction: false,
        }}
        pagination={{ clickable: true }}
        navigation={true}
        loop={true}
      >

        {/* Slide 1 */}
        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1607083206968-13611e3d76db?w=1600"
            alt="Sale Banner 1"
          />
        </SwiperSlide>

        {/* Slide 2 */}
        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1586880244386-8b3c5f5b5b3b?w=1600"
            alt="Sale Banner 2"
          />
        </SwiperSlide>

        {/* Slide 3 */}
        <SwiperSlide>
          <img
            src="https://images.unsplash.com/photo-1607082348824-0a96f2a4b9da?w=1600"
            alt="Sale Banner 3"
          />
        </SwiperSlide>

      </Swiper>

    </div>
  );
}

export default Banner;
